import './Contact.css';

const Contact = () => {
  return (
    <div className="contact-container">
      <h1>Contact Me</h1>
      <p>Email: your.email@example.com</p>
      <p>LinkedIn: linkedin.com/in/yourprofile</p>
      <p>GitHub: github.com/yourprofile</p>
    </div>
  );
};

export default Contact;
